@startuml
left to right direction
skinparam classAttributeIconSize 0
skinparam classFontName "Arial"
skinparam classFontColor #000000
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classBorderThickness 1
skinparam noteBackgroundColor #FFFFE0
skinparam noteBorderColor #333333
skinparam noteBorderThickness 1
skinparam noteFontName "Arial"
skinparam noteFontColor #000000

class "Context" as Context {
  <<C>>
  Strategy strategy
  +setStrategy(Strategy strategy)
  +execMethod()
}

class "Strategy" as Strategy {
  <<I>>
  Strategy : method()
}

class "StrategyImp1" as StrategyImp1 {
  <<C>>
  method()
}

class "StrategyImp2" as StrategyImp2 {
  <<C>>
  method()
}

note right of Context
  public void execMethod() {
    strategy.method();
  }
end note

Context --> Strategy : aggregation
StrategyImp1 ..|> Strategy : implements
StrategyImp2 ..|> Strategy : implements

note bottom of StrategyImp2
  策略模式
end note

@enduml
